const khojToken = $env.KHOJ_TOKEN || '';
const hostURL = $env.KHOJ_HOST_URL || 'https://app.khoj.dev';
const lastSync = $env.LAST_SYNC ? JSON.parse($env.LAST_SYNC) : [];
const filePaths = $env.FILE_PATHS ? JSON.parse($env.FILE_PATHS) : [];
const folderPaths = $env.FOLDER_PATHS ? JSON.parse($env.FOLDER_PATHS) : [];

return {
  khojToken,
  hostURL,
  lastSync,
  filePaths,
  folderPaths,
  regenerate: false
};

const filePaths = $input.all()[0].json.filePaths || [];
const folderPaths = $input.all()[0].json.folderPaths || [];
const lastSync = $input.all()[0].json.lastSync || [];

let filesToSync = [];

for (const filePath of filePaths) {
  const lastSyncEntry = lastSync.find(s => s.path === filePath);
  if (!lastSyncEntry) {
    filesToSync.push({ path: filePath, type: 'file' });
  }
}

for (const folderPath of folderPaths) {
  filesToSync.push({ path: folderPath, type: 'folder' });
}

return { filesToSync, lastSync };

const filesToSync = $input.all()[0].json.filesToSync || [];
const khojToken = $input.all()[1].json.khojToken;
const hostURL = $input.all()[1].json.hostURL;

if (!khojToken || !hostURL) {
  return { error: 'Missing khoj token or host URL', skip: true };
}

if (filesToSync.length === 0) {
  return { skip: true, message: 'No files to sync' };
}

return {
  filesToSync,
  khojToken,
  hostURL,
  syncUrl: `${hostURL}/api/content?client=automation`
};

const response = $input.all()[0].json;
const filesToSync = $input.all()[1].json.filesToSync || [];
const currentTime = new Date().toISOString();

const lastSync = filesToSync.map(file => ({
  path: file.path,
  datetime: currentTime
}));

return {
  success: true,
  lastSync,
  syncedCount: filesToSync.length,
  timestamp: currentTime
};

const result = $input.all()[0].json;
return {
  completed: result.success,
  error: result.error || null,
  syncedFiles: result.syncedCount || 0,
  lastSync: result.lastSync || []
};

const khojToken = $input.all()[0].json.khojToken;
const hostURL = $input.all()[0].json.hostURL;
const filesToPush = $input.all()[0].json.filesToSync || [];
const regenerate = $input.all()[0].json.regenerate || false;

if (!khojToken || filesToPush.length === 0) {
  return { error: 'Missing token or files', statusCode: 400 };
}

const method = regenerate ? 'PUT' : 'PATCH';

return {
  method,
  url: `${hostURL}/api/content?client=desktop`,
  headers: {
    'Authorization': `Bearer ${khojToken}`
  },
  files: filesToPush
};
